INSERT INTO t_p67171637_yug_transfer_prize_l.bot_daily_posts (photo_url, greeting, description) VALUES
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/10a7c723-4903-40ec-8071-8f27fd3e38ba.jpg', '🚕 Встретим в аэропорту с табличкой!', 'Водитель будет ждать в зоне прилёта с вашим именем. Поможем с багажом и довезём до места.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/8300d35d-9451-4769-9e10-8d1ed4c6f7a6.jpg', '🚕 Дорога вдоль моря — одно удовольствие!', 'Живописные маршруты по побережью. Любуйтесь видами, пока мы ведём машину.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/ce6e0f56-8436-48fe-b625-8ec35a6beb00.jpg', '🚕 Зарядка и вода — уже в салоне!', 'Заботимся о комфорте: подзарядите телефон и освежитесь в дороге бесплатно.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/86965868-3373-470e-a54c-024592728ba8.jpg', '🚕 Встречаем у вокзала точно к поезду!', 'Следим за расписанием. Опоздал поезд — подождём без доплаты за ожидание.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/a039bd78-a9e8-4f89-a26a-9e20298215e4.jpg', '🚕 Ранний вылет? Подадим авто к рассвету!', 'Забронируйте заранее — будем у подъезда вовремя, даже на самый ранний рейс.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/ba8d9757-6e9a-45f4-949c-b8ce8209b211.jpg', '🚕 Поможем пожилым пассажирам!', 'Вежливые водители помогут сесть, донесут сумки и довезут аккуратно до двери.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/537e0469-a904-4eaa-8360-a6ac30b6ef9e.jpg', '🚕 Закажите авто прямо в чате!', 'Напишите нам — и машина уже в пути. Быстро, удобно, без лишних звонков.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/bd955b7f-0e43-4178-902a-645bc9d0942d.jpg', '🚕 Деловая встреча? Подадим бизнес-класс!', 'Премиальные авто и водитель в костюме. Произведите впечатление с первой минуты.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/d4e24417-afd9-42d1-8d62-fd7575af0fc0.jpg', '🚕 Дождь не помеха — едем в тепле и сухости!', 'В любую погоду доставим с комфортом. Под дождём вас встретит уютный салон.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/a2194ca6-4b8a-4e46-847d-0c35c512dcf2.jpg', '🚕 На море всей семьёй — с комфортом!', 'Просторный минивэн для семьи и пляжных вещей. Отдых начинается с дороги.');